INSERT INTO public.courts (name, address, city, district, lat, lng, rating, rating_count, phone, google_maps_url, booking_url, place_id, thumbnail_url, images, opening_hours, reviews_data, popular_times, amenities, tags, highlight, hours_open, hours_close) VALUES ('Pickleball Cao Thắng', '151 Lý Tự Trọng, Thanh Bình, Hải Châu, Đà Nẵng 550000, Vietnam', 'Da Nang', 'Thanh Bình, Hai Chau', 16.078856, 108.213201, 3.8, 10, '+84 905 177 667', 'https://www.google.com/maps/place/Pickleball+Cao+Th%E1%BA%AFng/data=!4m7!3m6!1s0x314219004702f195:0x3cff11d9d42f43db!8m2!3d16.0788561!4d108.2132013!16s%2Fg%2F11x800q0mh!19sChIJlfECRwAZQjER20Mv1NkR_zw?authuser=0&hl=en&rclk=1', NULL, 'ChIJlfECRwAZQjER20Mv1NkR_zw', 'https://lh3.googleusercontent.com/gps-cs-s/APNQkAF8jJfD3Jo68gTdK5QHXAYB9OtE8Yrx6bLyfx8Rn63KFWqAs9IgixGJdArIEmGan_t7KaDeJJEQTFmy7-KrqY_tst8jAKw31fE9p6moxfplUojV8ZiRzw8HnxonxVngKLG5x_dzl7VeQK7_=w408-h306-k-no', '[{"title": "All", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAF8jJfD3Jo68gTdK5QHXAYB9OtE8Yrx6bLyfx8Rn63KFWqAs9IgixGJdArIEmGan_t7KaDeJJEQTFmy7-KrqY_tst8jAKw31fE9p6moxfplUojV8ZiRzw8HnxonxVngKLG5x_dzl7VeQK7_=w397-h298-k-no"}, {"title": "Street View & 360°", "image": "https://streetviewpixels-pa.googleapis.com/v1/thumbnail?panoid=h16Y_P3eEPImAry5cabEiA&cb_client=maps_sv.tactile.gps&w=224&h=298&yaw=242.39745&pitch=0&thumbfov=100"}]'::jsonb, '{"Friday": ["5 a.m.–10 p.m."], "Monday": ["5 a.m.–10 p.m."], "Saturday": ["5 a.m.–10 p.m."], "Sunday": ["5 a.m.–10 p.m."], "Thursday": ["5 a.m.–10 p.m."], "Tuesday": ["5 a.m.–10 p.m."], "Wednesday": ["5 a.m.–10 p.m."]}'::jsonb, '[{"Name": "Thi Phuong Nga Tran (Mèo)", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjXqj3YEr71AA_k49U0N_BN_OwpQu-O62O0R8J1cQc6n9kynmv3FvQ=s120-c-rp-mo-ba4-br100", "Rating": 5, "Description": "Sân Pick đạn thoải mái, có phục vụ nước, sữa chua, chị chủ thân thiện nhiệt tình!", "Images": null, "When": ""}, {"Name": "THIEN QUANG", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjV62pTph-DOZyn-OA0wNoVYzUmC6AQSKtwM28L4U4Y_O4_4NqTQXg=s120-c-rp-mo-br100", "Rating": 5, "Description": "Sân pick sang xịn mịn, mn vui vẻ !", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn2RfW1Qne9FHn-6z1WIj06yffayNL-VNiRwokr_CyWTK8fRZtvaYWusAnXXObCYcfzW8ql-vePkj2lLiIu4E7fa88yNUlQjAAtcmM2qVXRMWbdayjpMvTsV4PIlXhwNqfZSwyELJJu8B-9W=k-no"], "When": "2026-1-21"}, {"Name": "Quan Le", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjUjGyFtpr3ugZH5lWXd5Xd7AQroSR2W30nogQAPyBtLLEnFeeqA=s120-c-rp-mo-br100", "Rating": 1, "Description": "Tôi và bạn bè đã có một trải nghiệm cực kỳ thất vọng tại sân pickleball này. Thái độ của chủ sân rất thiếu chuyên nghiệp, tỏ ra khó chịu và cáu gắt khi chúng tôi hỏi về thời gian đặt sân cũng như cơ sở vật chất.\n\nSân cực kỳ bẩn, rác chưa được dọn, nền sân có nhiều vết ố và thậm chí có chỗ còn trơn trượt nguy hiểm. Không gian thì nóng nực, không có hệ thống thông gió hay quạt mát đầy đủ, khiến việc chơi thể thao trở nên mệt mỏi và khó chịu.\n\nCơ sở vật chất đã cũ kỹ, xuống cấp trầm trọng, các vạch sân mờ, lưới thì rách, và không có khu vực nghỉ ngơi hay để đồ sạch sẽ. Nhà vệ sinh thì bẩn và có mùi, rõ ràng không được dọn dẹp thường xuyên – hoàn toàn không đảm bảo vệ sinh và an toàn cho người chơi.", "Images": null, "When": ""}, {"Name": "Phúc Lê", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocJU3K1z4K45XgES2f8lQ_TRUW82aZkGHqOKrsv4vFRLTBsGrw=s120-c-rp-mo-br100", "Rating": 5, "Description": "Sân đẹp, mát mẻ, chị chủ nhiệt tình, dễ thương", "Images": null, "When": ""}, {"Name": "HA VO LE NGOC", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocITw6Zjcw1-F78mjJ5gjin6NSdLvv945kYzoCsxlQ6qfGTesA=s120-c-rp-mo-br100", "Rating": 5, "Description": "Anh chị chủ thân thiện, tuyệt vời.", "Images": null, "When": ""}, {"Name": "Ta Huong", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocKdLEtx1PkMa_CDL9tZDjQa_8i3KyYTuUoivvLJS07-wRg7hQ=s120-c-rp-mo-br100", "Rating": 5, "Description": "Bà chủ nhiệt tình", "Images": null, "When": ""}, {"Name": "Pông OHelix", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocKxfoeJ2GyFlcxruAeNUMFgjTSiOfHkuVZwSA3IJuoiXA6RLg=s120-c-rp-mo-br100", "Rating": 1, "Description": "nóng", "Images": null, "When": ""}, {"Name": "Tran Hieu", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocKKTTIm-pN7bRD5QHJUi7Ml4tDJcpd6uGTDPDy9EmpgHeR33w=s120-c-rp-mo-br100", "Rating": 1, "Description": "nóng, chủ sân thái độ tệ", "Images": null, "When": ""}]'::jsonb, '{"Friday": {"10": 50, "11": 50, "12": 44, "13": 33, "14": 50, "15": 50, "16": 61, "17": 83, "18": 88, "19": 100, "20": 72, "21": 72, "4": 0, "5": 44, "6": 38, "7": 38, "8": 33, "9": 61}, "Monday": {"10": 44, "11": 55, "12": 44, "13": 44, "14": 22, "15": 16, "16": 22, "17": 33, "18": 38, "19": 77, "20": 77, "21": 100, "4": 0, "5": 50, "6": 66, "7": 72, "8": 61, "9": 55}, "Saturday": {"10": 61, "11": 55, "12": 61, "13": 38, "14": 22, "15": 27, "16": 50, "17": 83, "18": 100, "19": 88, "20": 77, "21": 38, "4": 0, "5": 38, "6": 27, "7": 22, "8": 33, "9": 38}, "Sunday": {"10": 61, "11": 44, "12": 44, "13": 38, "14": 38, "15": 50, "16": 55, "17": 38, "18": 27, "19": 27, "20": 38, "21": 66, "4": 0, "5": 55, "6": 55, "7": 50, "8": 55, "9": 61}, "Thursday": {"10": 27, "11": 22, "12": 22, "13": 16, "14": 11, "15": 22, "16": 38, "17": 66, "18": 77, "19": 72, "20": 61, "21": 33, "4": 0, "5": 38, "6": 38, "7": 33, "8": 33, "9": 33}, "Tuesday": {"10": 61, "11": 72, "12": 77, "13": 55, "14": 44, "15": 44, "16": 55, "17": 66, "18": 61, "19": 44, "20": 33, "21": 16, "4": 0, "5": 33, "6": 50, "7": 61, "8": 61, "9": 44}, "Wednesday": {"10": 22, "11": 27, "12": 44, "13": 38, "14": 50, "15": 55, "16": 55, "17": 66, "18": 77, "19": 61, "20": 50, "21": 44, "4": 0, "5": 66, "6": 50, "7": 50, "8": 33, "9": 22}}'::jsonb, '[{"id": "amenities", "name": "Amenities", "options": [{"name": "Washroom", "enabled": true}]}]'::jsonb, ARRAY['Fitness center', 'Washroom'], NULL, '05:00', '22:00') ON CO