INSERT INTO public.courts (name, address, city, district, lat, lng, rating, rating_count, phone, google_maps_url, booking_url, place_id, thumbnail_url, images, opening_hours, reviews_data, popular_times, amenities, tags, highlight, hours_open, hours_close) VALUES ('PINPON SPORT Badminton 24/7', 'Đường Số 6, An Hải, Sơn Trà, Đà Nẵng 550000, Vietnam', 'Da Nang', 'An Hải, Son Tra', 16.076829, 108.237634, 4.5, 42, '+84 898 200 700', 'https://www.google.com/maps/place/PINPON+SPORT+Badminton+24%2F7/data=!4m7!3m6!1s0x314217005dabcbeb:0xad9a8a97d4aa9d79!8m2!3d16.0768289!4d108.2376344!16s%2Fg%2F11w7zwtjcp!19sChIJ68urXQAXQjEReZ2q1JeKmq0?authuser=0&hl=en&rclk=1', NULL, 'ChIJ68urXQAXQjEReZ2q1JeKmq0', 'https://lh3.googleusercontent.com/gps-cs-s/APNQkAFRhmAHOdG3olUrKNVMPHl_U6h3WdpUt5Zm0hsfmGGfDTM0ezYDIW3f8zMCWI9mpgyWFToeNz417NbPnSWKavXEDK6zfQDm5DSGu9HZFKv7YALU_mzVzXGlukIw9nEUEQZrdfn-=w408-h544-k-no', '[{"title": "All", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAFRhmAHOdG3olUrKNVMPHl_U6h3WdpUt5Zm0hsfmGGfDTM0ezYDIW3f8zMCWI9mpgyWFToeNz417NbPnSWKavXEDK6zfQDm5DSGu9HZFKv7YALU_mzVzXGlukIw9nEUEQZrdfn-=w224-h298-k-no"}, {"title": "By owner", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAH7VpbhkC_djcleeoSNJWc4PPZ7ydWWac8yJyqFgauA5mPqgHJ5FvbK_FDRENHWAVTEWF3Wi4VK5ZKlxj0SMSdtOuVViZf0EiPtAXEGCWHrq4NZZf9m4r_XYiG7Mz45uSqSD4j1=w224-h298-k-no"}, {"title": "Videos", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAH1MLTobS1zno3M2lWgplBFad5B83-X5UBK3ryltcHmr27pvWfhnM0AlvbPel2stg2D-kMfp3_QEB4emepchbTFfLU7ksmuqZrbLVmfC9LOlQ802hCI9ruY9DhxteG1MGLyVGwdJC7KSIVR=w224-h398-k-no"}, {"title": "Street View & 360°", "image": "https://streetviewpixels-pa.googleapis.com/v1/thumbnail?panoid=SpLeFQCcb1n5rX8d1FRBGQ&cb_client=maps_sv.tactile.gps&w=224&h=298&yaw=294.42886&pitch=0&thumbfov=100"}]'::jsonb, '{"Friday": ["Open 24 hours"], "Monday": ["Open 24 hours"], "Saturday": ["Open 24 hours"], "Sunday": ["Open 24 hours"], "Thursday": ["Open 24 hours"], "Tuesday": ["Open 24 hours"], "Wednesday": ["Open 24 hours"]}'::jsonb, '[{"Name": "Anastasiia Datsenko", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjVsMTVlvKm6Iw2OyltwqTYhumm_p1YHWFcAYN3TPOXEHlmj7AJE=s120-c-rp-mo-ba4-br100", "Rating": 5, "Description": "Super clean, no weird smells, everything’s in great condition, from the courts to the rackets.\n\nThere’s water, which is a lifesaver, because it gets HOT. Like really hot. So wear something light and bring a towel unless you wanna leave looking like you took a swim 😅\n\nBut it’s fun, clean and great for a good laugh (and workout) with your people. I’ll be back and next time with extra deodorant lol 😜", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn0lm0lNfQNgc4tk2Vzb3dRdAzuLy_HE01tc-Cr1G6Im8BMXMP-izKDrMJw8M9FsLrY1W02mD8Qj9C1QT_p0WRZaU6qcYRTb7-ltli3cKbzGTOEnb_TNCGK3HV5w196QG4w_E2Z155L0q6jv=k-no"], "When": "2025-7-26"}, {"Name": "Billy D Baker", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjX2UKQReFcEUlYAtRZdBjeopVBJXYdkJsyxSgYmNPJqzgSC92j5=s120-c-rp-mo-ba5-br100", "Rating": 5, "Description": "Excellent courts and good vibes here.  A fun place to play.", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn1ysXZJi9ZxqP-q7zdk_tFJI0u67h4svI9eTywKCDTMIdfLDDh_v_C-GlvpX0GEi8-AMCYnjnY1whlli-8dVwtahTql1Lt8HxZvgHR7qHhdDyzbSfNeiyApnna236aj8DNxNH95=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn3a4pzbd9FDMJO2hJHlir0Ot4UOiWo5DopDOeXF4i6cGOMmDdirYBUDMzWYy_Zy488mmN4ea68bWwZ2-o3G-daAJXsfzgaLHgEAksCZt9W1Tca895jBFvYJoIqzTyL7XdGaqmB4YA=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn2VTgGW0Y-Frumbb9x7s4GadM8C67qkGKDjCBH-u08x7SEA1SQ3rw8NMlVbm1tsh3c7V6zhSVnPKiMyi_Pythkujo9eInpf-t3i7v3YxlwNjjsobYBQgxiorKsqsL8BB-TPjROm=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn3QPjnGwjEanC7H4mBpQ8iGPOv1y9IV-xhOhywFUZs5N4N3-vIITrWlMjsENlQDNcR9wvUodXdca_eD4MZ0CvAklGLe4CvvOVqpUdjmP8M9TYbp1UCW1axAd3MxhD1mht92YAKrOg=k-no"], "When": "2025-2-7"}, {"Name": "Phu My (Trip)", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjVoP4Q-Pq1pC2BiX9HRv49OEvkcmYZPnaj6wBX6BlDUpCU4_43Djw=s120-c-rp-mo-ba5-br100", "Rating": 5, "Description": "Good", "Images": null, "When": ""}, {"Name": "Thuy Ngo", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjUET9YQIxGUNEkfcEcLCbS7DJbl4RQ8v4viHsnxQ1cHc4U2jNY=s120-c-rp-mo-ba4-br100", "Rating": 5, "Description": "Sân cầu lông mình yêu thích nhất tại Đà Nẵng.\nSân chia làm 2 khu, mỗi khu 3 sân rộng rãi, đánh có thể nghe được tiếng cầu không quá ồn như các sân khác. Chỗ ngồi rộng rãi, thoải mái, trang bị đầy đủ các dụng cụ, ổ cắm điện sạc điện thoại có giá treo điện thoại, có cả tripod để quay video ^^\nChủ sân dễ thương, nhiệt tình, thân thiện, rất welcome khách hàng. Highly recommend mọi người đến sân này ạ!!!!", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn2ZdG4Y0kWoSqvWuAiiwLOtJfrlKWk9O9j_SKX_W6O4V2nFpVmEDK8mTlcX72kWyrBnVUwDucLt-i-eYQgCi1mGZWVY072CHbM5yjYM79sV4SR9WKtubhEBsOse9hPZc4gvbm2TeQ=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn2RqmEeyNOeTwMPARNBbsMwKJbpDscFPwCemQCorDK_AHXbxJcSD2gLrhYZcjjWDnFXmNlhtWYHk_QX2ROwO0_ndBcfM1u_RuaoBpkejuxDpVVi32sGSWAby0NZS5CObA-Qw3LJ=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn20CQlNQLctkcrYjp8anFoQRkdL5C8q04c21yJK8iH1HVbV4H-HAj-oalrVr7wnDpTpyd4jNaLSXM2ocyeU6bsc_BKlDMNsh7UZy_KdcsH27jeee34zg0gs-q_v00dt6MOSPmzImA=k-no"], "When": "2025-3-31"}, {"Name": "Kieu Ngan Nguyen", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjXJ7XHjg9RZ9ZdHCCPDLsiZ_y2ubgnQoZNerRahY-HU2QC-vxqR=s120-c-rp-mo-ba5-br100", "Rating": 5, "Description": "Đi vào theo gg maps là tới, sân thảm nên cần phải đi giày thể thao đế mềm mới được vào sân nhé, không dùng được các loại giày có đế nhọn. Sân khá mới, rộng rãi, có cho mượn bục trao giải, ghế trọng tài, bảng điểm và căng băng rôn giải đấu. Mình đặt 2 tiếng giá khoảng 240k. Có quạt và ổ điện xung quanh nên ngồi cũng không bị nóng. Buổi tối ở đây khá đông người tới chơi.", "Images": ["https://lh3.googleusercontent.co