Picture": "https://lh3.googleusercontent.com/a/ACg8ocI-PvqEpKCCHAVZ19FUrwRX97JpAjzFs4G3zHt--m6MjkMCLtE=s120-c-rp-mo-ba3-br100", "Rating": 5, "Description": "", "Images": null, "When": ""}]'::jsonb, '{}'::jsonb, NULL, ARRAY['Pickleball court'], NULL, NULL, NULL) ON CONFLICT (place_id) DO UPDATE SET name = EXCLUDED.name, address = EXCLUDED.address, city = EXCLUDED.city, district = EXCLUDED.district, lat = EXCLUDED.lat, lng = EXCLUDED.lng, rating = EXCLUDED.rating, rating_count = EXCLUDED.rating_count, phone = EXCLUDED.phone, google_maps_url = EXCLUDED.google_maps_url, booking_url = EXCLUDED.booking_url, thumbnail_url = EXCLUDED.thumbnail_url, images = EXCLUDED.images, opening_hours = EXCLUDED.opening_hours, reviews_data = EXCLUDED.reviews_data, popular_times = EXCLUDED.popular_times, amenities = EXCLUDED.amenities, tags = EXCLUDED.tags, highlight = EXCLUDED.highlight, hours_open = EXCLUDED.hours_open, hours_close = EXCLUDED.hours_close;
INSERT INTO public.courts (name, address, city, district, lat, lng, rating, rating_count, phone, google_maps_url, booking_url, place_id, thumbnail_url, images, opening_hours, reviews_data, popular_times, amenities, tags, highlight, hours_open, hours_close) VALUES ('SeaMart Pickleball', '146 Duy Tân, Hòa Thuận Nam, Hòa Cường, Đà Nẵng 560000, Vietnam', 'Da Nang', 'Hòa Thuận Nam, Hoa Cuong', 16.052166, 108.206564, 4.1, 15, '+84 799 467 146', 'https://www.google.com/maps/place/SeaMart+Pickleball/data=!4m7!3m6!1s0x314219000a0ad46b:0x7c2f066d8de875d7!8m2!3d16.0521656!4d108.2065643!16s%2Fg%2F11x8dnv_tn!19sChIJa9QKCgAZQjER13XojW0GL3w?authuser=0&hl=en&rclk=1', NULL, 'ChIJa9QKCgAZQjER13XojW0GL3w', 'https://lh3.googleusercontent.com/gps-cs-s/APNQkAGPu0b6wgv8SGuka_c7tm6CFjw2nc02-8QM2jsdiJzfNqWPVjJjD9tfJgeKvYVBjFQj3PPX4_UBPPpyP7zMsVUmPLj5E6wx5KVNkdemWWfS2oIoMb9_e8DCJpmPM_nd_kn8uZvGHwZg7pME=w408-h544-k-no', '[{"title": "All", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAGPu0b6wgv8SGuka_c7tm6CFjw2nc02-8QM2jsdiJzfNqWPVjJjD9tfJgeKvYVBjFQj3PPX4_UBPPpyP7zMsVUmPLj5E6wx5KVNkdemWWfS2oIoMb9_e8DCJpmPM_nd_kn8uZvGHwZg7pME=w224-h298-k-no"}, {"title": "Street View & 360°", "image": "https://streetviewpixels-pa.googleapis.com/v1/thumbnail?panoid=A1M5kkuFB34xKL2rFrrtJg&cb_client=maps_sv.tactile.gps&w=224&h=298&yaw=173.48909&pitch=0&thumbfov=100"}]'::jsonb, '{}'::jsonb, '[{"Name": "Lien Nguyen", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjWaAF7cGQx-Q4E_DrIIw1YSdwJSxFCGjumpaO9v0YNlccyXtpq4=s120-c-rp-mo-ba6-br100", "Rating": 5, "Description": "👍 Ưu điểm\n•\tSân có 7 sân con chuẩn pickleball tại địa chỉ 146 Duy Tân.  ￼\n•\tGiờ mở cửa linh hoạt: khoảng 5:00 sáng đến 23:00 hàng ngày.  ￼\n•\tGiá thuê khá rõ: khoảng 120 – 160 🐠/giờ tùy khung giờ.  ￼\n•\tVị trí trung tâm Quận Hải Châu nên dễ tiếp cận, tiện cho đánh sau giờ làm hoặc cuối tuần.\n\n⚠️ Lưu ý\n•\tVì nằm trong khu vực đô thị và có nhiều người đặt sân nên giờ cao điểm (chiều tối) thường full, bạn nên đặt trước nếu đi nhóm.  ￼\n\n🎯 Gợi ý khi đến\n•\tĐặt sân trước online hoặc gọi điện để chắc chắn có giờ đẹp, đặc biệt là từ 17:00 đến 20:00 là dễ đông.\n•\tNếu bạn mới chơi, nên đến sáng sớm hoặc đầu giờ chiều khi ít người hơn để dễ hẹn đánh, thoải mái thử sân.", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn3DYjq4AuiZGKf_rinV6s4AQumCqq7D7gXO9Dm0apivUf2h0O0sJ1siHjyo2wHtaWEMOIEgrEEwZbU3tN-q6r_CFQIiTH_dyAhkMStwM8bIcu6haLMwil7Cj1SN2Ljzxs1mKoZbO9vezX-g=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn1G6rglVPg93J0s1QzpM8jdrotEYJtHcjtZOA321UDw3Link-nmmNt62IYSvTD9dwmUGmWHrp1D2WdnWHwFATkx0wD9O9TYUAWfxLH6w4C5cBMBMWW9xYLXySKo1u6M3FDlMLa9vjct-2hJ=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn1mg6mDls2mEIB9NjY2VdUxxySjbZUynIuLkxB9tDQWws9wf1AbnpZTe6dgUIsgc_v_znYbpuJEcpx4OH_P31ATQQkUCystcyWf6LkOV5ENTBqaj2fyGMWnhQXtohtVID2SfjUtfZFcM2E=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn28nUsh4JEEn5N6F3EQ-21PEaA7_TR9cupioQpNKabJxUiZn8fhTYR-MuDdNtns8uU06MNGRUWlTFz5LUGOu6r7Ze52sRA6h6CR_hZ-Ar_vT3Y2Ld8zIUuZUR8Yot08uHb1zDtlA1Sfs-c=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn2phXs69fdAvLWT7GlXqLyuRF2pj4ODFpaySRcOIsyMcgql5xAHRcWQk_vph-N_z4MMnmP0rljcMfYLek1jX3gtCJ7lCTdI1h11FhuQDhqGyagbioeQpdOpX1e5Ay_Pri4boIQRkZHTTmdM=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn29QwRgEwEFvS6FooMhaajhiXbtlxGkc4xey--Pt-QF_mSpSKf17ODYyPPvSgrLR4sTClXcveRPU6MeV7TTWwOWOEDhCQrDC2LT_f6S_poa2jd39ut7oVFJ4zvLiHWsTtvjKwGuN-S8JIm-=k-no"], "When": "2025-11-9"}, {"Name": "Danh Phạm", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjXrm5xRlZ3jzTqToEBHsRhE3rGaBioUrXFikvU-KUiFz1WngO1k=s120-c-rp-mo-ba4-br100", "Rating": 3, "Description": "Sân pickleball rộng , rãi , nhưng mùi khai từ WC khó chịu quá", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn2HyAjVQYgM4xUR5vVJ2ajVFrXAF_olPQv0hM0WO4-V3lAWaFzLYjvcFce14Kghkjn-N0LawiYQCkXznLUDnJL-fVwASzNUeJCj4VPjbD4R8HMRvJHDri1uOxpPGBO8NdBvnSkB8BSJNKCY=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn2l