Wednesday": ["Open 24 hours"]}'::jsonb, '[{"Name": "Nhanh Nguyen", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjVSm51OOdyglpXh29pcCdWxv6jKPorhFOI0Lfc6hJzsw7RW6xA=s120-c-rp-mo-br100", "Rating": 5, "Description": "Thanks for an excellent experience. The Pickleball court here is designed to be spacious, airy, clean, and fully equipped with modern facilities, along with many other convenient services.", "Images": null, "When": ""}, {"Name": "GOOD VUONG", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjVugzcrQKSLsswKN_WZwE5LtW6WuAOerg1dwjcu7cioulTpzJwW=s120-c-rp-mo-br100", "Rating": 5, "Description": "Great", "Images": null, "When": ""}, {"Name": "Bảo Nguyễn", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocKlMpHBo0LGGoxhoRF9WUnNofgLAMHtzqyvLwQyWXB4KR6rnA=s120-c-rp-mo-br100", "Rating": 5, "Description": "Ok", "Images": null, "When": ""}, {"Name": "Vinh Si", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjUvjtL58lC2tkBmyFrg55JfEJAPEVq5FgZxnV-gngNnh_lEFCc=s120-c-rp-mo-ba6-br100", "Rating": 5, "Description": "Sân đánh tốt. Có thể kéo bạt lấy ánh sáng cho sân. Chị chủ tốt bụng cho mượn cả vợt và banh tập. Điểm cộng nữa là nhà vệ sinh rất sạch sẽ", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn3cGxx6tNkz9bFTlFRER5XQszKPTbhS8ms4C6xGQstn8bcf5FB7A3tIqCsvgPheM9bg5dUdE53HzFmUjwSRHLTq4tN6SiDOi0toKB78LdJo5HnpttEpi1kK3d9jjb3q1jEpMSVM-CNzrvwg=k-no"], "When": "2025-12-26"}, {"Name": "Ha Nguyen", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjXA_cBS_c70eCbJgefm6DVy790bWkMSGV8BiloYm1xtRvPNHfEK=s120-c-rp-mo-br100", "Rating": 5, "Description": "Sân pick rộng rãi, thoáng mát nhất khu vực Hoà Xuân - Cẩm Lệ. Mặt sân nhựa đường nên bóng nảy tốt, đặc biệt giá cả hợp lý, chủ sân thường xuyên hỗ trợ giảm giá nếu đặt sân ổn định lâu dài. 💯💯", "Images": null, "When": ""}, {"Name": "Thị Hiền Uyên Trần", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocLHwYpEbJLkP4MIqk4uKSCheSJeiGjDfcWSZzAo_DzQLoh9tw=s120-c-rp-mo-br100", "Rating": 5, "Description": "Không gian sân rất thoáng đãng, sạch sẽ, bề mặt sân bám chân và đặc biệt rất thích chủ sân và nhân viên về sự nhiệt tình. Sẽ ủng hộ sân dài dài!", "Images": null, "When": ""}, {"Name": "Giang Huy Đỗ", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjVphZAwoX30qSztggvNn8ZKre0rm5OUVd58Px8T2Eullp2x6CPY=s120-c-rp-mo-br100", "Rating": 5, "Description": "Nền sân ổn định, đạt tiêu chuẩn thi đấu các giải lớn. Không gian thoáng cafe thoải mái, cảm ơn Zone 43 đã tạo thêm cho cộng đồng Pickleball Đà Nẵng một địa điểm đáng đến chơi và trải nghiệm.", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn3PLh57I1Df3Z7HKeSAutYImR935Bq9NP4yxjaI-3MTMVru-S2B23uP9T0_Q-RvGMQHgU02zxBzqIsCfr22XHt1eiSaf0YXY6xKldsW8Qk_vtHFIeWixm3J4RKojwzgLmo2BD8=k-no"], "When": "2025-4-21"}, {"Name": "Thiên Ngô Bảo", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjXKB2L_6vct9l7T3bXiiEbEcIe5a5GOw-jM68vuq7onM5y_C2t4=s120-c-rp-mo-ba7-br100", "Rating": 5, "Description": "Mặt sân ổn, không gian thoáng. Anh chị chủ sân nhiệt tình vui vẻ", "Images": null, "When": ""}]'::jsonb, '{"Friday": {"0": 22, "1": 17, "10": 17, "11": 15, "12": 20, "13": 33, "14": 40, "15": 51, "16": 53, "17": 55, "18": 53, "19": 46, "2": 20, "20": 28, "21": 15, "22": 15, "23": 15, "3": 17, "4": 22, "5": 26, "6": 28, "7": 22, "8": 17, "9": 20}, "Monday": {"0": 24, "1": 37, "10": 44, "11": 42, "12": 28, "13": 28, "14": 42, "15": 64, "16": 73, "17": 77, "18": 73, "19": 66, "2": 33, "20": 42, "21": 24, "22": 11, "23": 13, "3": 24, "4": 20, "5": 20, "6": 17, "7": 24, "8": 31, "9": 46}, "Saturday": {"0": 4, "1": 8, "10": 44, "11": 37, "12": 40, "13": 44, "14": 55, "15": 68, "16": 82, "17": 82, "18": 66, "19": 53, "2": 15, "20": 35, "21": 20, "22": 13, "23": 4, "3": 20, "4": 28, "5": 40, "6": 51, "7": 62, "8": 60, "9": 55}, "Sunday": {"0": 26, "1": 24, "10": 37, "11": 35, "12": 31, "13": 40, "14": 57, "15": 75, "16": 73, "17": 60, "18": 40, "19": 22, "2": 15, "20": 