INSERT INTO public.courts (name, address, city, district, lat, lng, rating, rating_count, phone, google_maps_url, booking_url, place_id, thumbnail_url, images, opening_hours, reviews_data, popular_times, amenities, tags, highlight, hours_open, hours_close) VALUES ('Pickleball Ca Ri Club', '17 Trảng Kèo 1, Hội An Tây, Đà Nẵng, Vietnam', 'Da Nang', 'Hoi An Tay', 15.896699, 108.321632, 5.0, 40, '+84 912 401 379', 'https://www.google.com/maps/place/Pickleball+Ca+Ri+Club/data=!4m7!3m6!1s0x31420f005f32f527:0x7c4a46b47e382270!8m2!3d15.8966989!4d108.3216322!16s%2Fg%2F11lyc2mfb2!19sChIJJ_UyXwAPQjERcCI4frRGSnw?authuser=0&hl=en&rclk=1', NULL, 'ChIJJ_UyXwAPQjERcCI4frRGSnw', 'https://lh3.googleusercontent.com/gps-cs-s/APNQkAEmHgdJPsihv9iYigDfX7Ot_l_lzncx-j3h5RPkOKWKLL6_tPvnIKTZc2MWA0YKGXq2gPCcAy1CkkWbQDAu-llz1wJkgZaSsWvMfwwKDXh5JYarfbv6CjQiJGsAog9iHbEtXL5EvWo_tbYM=w408-h307-k-no', '[{"title": "All", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAEmHgdJPsihv9iYigDfX7Ot_l_lzncx-j3h5RPkOKWKLL6_tPvnIKTZc2MWA0YKGXq2gPCcAy1CkkWbQDAu-llz1wJkgZaSsWvMfwwKDXh5JYarfbv6CjQiJGsAog9iHbEtXL5EvWo_tbYM=w395-h298-k-no"}, {"title": "Latest", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAEzqWsZzipDzBzPy02szLV0pauvgmzlsLKPdbRuse2pS4xjBeXlHnBMf-OkK8HeV4pkVr-W0uk84poWD5tITL9A7LVL69p5QP2UA72G4m_sw8ORssyC4cBoPmYcJCL4FKgd_YFBrodr3XZw=w224-h485-k-no"}, {"title": "Videos", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAHmvkP6FxI5upD8I8B-DDS-6L3cajTitF6_BPVHvTLN9Z_d6aOaa9n-d0hdO2nb-buIJFY02stCmQ-1vqR_5GiPcaQ5q_FQ84HLJ8mg-VPNSvpFJTbg9E9kMsDUrtLeh-aCWbXikSyfcLY=w529-h298-k-no"}, {"title": "Stadium", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAFPuj54jrmvTO_w3db0mQg_1LwEnaoFjnaYYqhMx4Sv1bSv6iXZPJRebJ3y1mA0CXsbJXlSfxv0dZSoDbDp6Z1Ed6dY--PoZEIHGGWQQQeXM09XP2GoUM1oLEIfNRZSS0Oh_UeRNBE_k2nY=w529-h298-k-no"}, {"title": "By owner", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAG302zK0WeGPzT8oSedKd7VxZrCjSZNZOoKDrPlr1xg4RaYJ4LjvaV37tWHJaTmyOeI16LMzeOraEWqHZdMAnlXo0LHTHh9wihvOlrZOr0E40YJ3YNAl7XbdNRNH1bOHweBjz-jCo0tK_kR=w397-h298-k-no"}, {"title": "Street View & 360°", "image": "https://streetviewpixels-pa.googleapis.com/v1/thumbnail?panoid=st0XE_I53Q5ezfxx70TSfw&cb_client=maps_sv.tactile.gps&w=224&h=298&yaw=146.8746&pitch=0&thumbfov=100"}]'::jsonb, '{"Friday": ["5 a.m.–10 p.m."], "Monday": ["5 a.m.–10 p.m."], "Saturday": ["5 a.m.–10 p.m."], "Sunday": ["5 a.m.–10 p.m."], "Thursday": ["5 a.m.–10 p.m."], "Tuesday": ["5 a.m.–10 p.m."], "Wednesday": ["5 a.m.–10 p.m."]}'::jsonb, '[{"Name": "Ryan G", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjU_x55VwEYHtIk8Uge-PSL6iXRuaj9DEOLvwE42eGG09Z50PASkqQ=s120-c-rp-mo-ba5-br100", "Rating": 5, "Description": "Me and my wife reached out to this Pickleball club as we are in Hoi An for a few days traveling and still wanted to get some Pickleball in. We got there before 10AM and waited for the owner to get there. Not too many people but the owner called a friend and we ended up playing a few competitive games. The courts are nice and new and they have nets around that keeps the balls from going everywhere. I would recommend this place to anyone looking to have fun and play some competitive pickleball.", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn2ChnrPsP9_psNmBLXldAud-QlezicKAwSA5Qc4pX5pgQO6N_fqBG5Gvvhby_Y9D_hnebBY9wNXUIXSrzrjZouGukznCm1OIQ0piXOKpj-WGaCLrNLZSEVxD5aeLqWeI5fNGJG7FohiZ1U0=k-no"], "When": "2026-3-7"}, {"Name": "DAVID ANDERSON", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocJiEgqaNcowr1eZC8Gvj1d58c1l3Ga2qKh2aka326bNazCBYw=s120-c-rp-mo-br100", "Rating": 5, "Description": "Great place to play daily social.\nOwner and his wife are so friendly & supportive of making your pickleball play a happy & competitive time…lessons available too…please stop by Ca Ri & support this small business….", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn1syQqIWVGxhkY3fsFYvIXvCODYwL0Euj4sr2wyqMH1jyw77fpq-_zaPCEDuFxHfcH0vsscfkFOmd3xkEgmYzqYYixDy-6-vuLtBb6UzOB3Og5dJ8ent14dC8ORbKghZVFbHpzm93iLlcg8=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn0qOESHLcqG_c5tDA3H7Q3bqm_n0XamuRl0NqTl2fCQ22yZ36fK7TC6ZYaLgt4We-m7-z1qP_pgMBItMRlCaaXD16CLF7pHwxa0tj0I2IPjoH6E3Pae16Ts6CW8DxCvDk9BVG92qHAzfLyE=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn1f19LXP-PCO-Jj2gFOaRC42ECoOXqfXfy2v2fO2D_0vYSqsIfsXMYV3MBanUfWXhovI4ZS5rIhdgUW5yt66D0FrAZffZkr9-26bXO8OrDUY5YsH09ZP5gJAM36Lwd4vxv2rPglA178xmvT=k-no"], "When": "2026-3-8"}, {"Name": "Blake Vincent", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjUnnoV_e-QfbrQD1alrErJ_Z4TUh2dKnjmObbParhBSkCHU9-Xu=s120-c-rp-mo-ba4-br100", "Rating": 5, "Description": "Amazing place to play pickleball in hoi an.\nPlayed my first ever match. Ended up playing on and off for 2 hours for 100VND.\nRacquets can be borrowed.\nVery cool environment even in the heat.\nAmazing staff and friendly players.\nWill be back!", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn1RIp6wW6e4gTcrZicjosynGe9a2IL9L0KeNpcwzc0-Snxuj7E7qNAKG4hThFPgHvrO_YYa0qwJgycSar_qU6yt_ZVsCnSjyHR0BhDLPMair3VSTf6LSK4V0sRRPdJLCB_uAhKQabZpNUYR=k-no"], "When": "2025-8-3"}, {"Name": "Kevin Murray", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocIqG3RFq1Mm6iBDVO3xPbkxoQroTxNog_69RNX6IQXdgrOQgA=s120-c-rp-mo-br100", "Rating": 5, "Description": "Played with my 13 year old son for the first time and it was great fun. Would recommend for those who find tennis, squash and badminton more difficult. The staff were extremely friendly and helpful.", "Images": null, "When": ""}, {"Name": "Nhựt Đoàn", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjWsNtcWyfRKi9RPnQ3BPV2Atj7_YTBovIZO00jZ7SFEnXQCL60=s120-c-rp-mo-br100", "Rating": 5, "Description": "The first time I came to the field. I felt the space was airy and clean. The yard was clean, the ground was soft, convenient for moving and hitting the ball with little injury. It met competition standards. I felt great. The brothers here were very friendly and welcoming, especially Coach Nhut Thang Binh, who played well and had powerful shots. See you again.", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn13B2Zz5TYhc5jpLcXZse486zsieloQWaHTgvPr8OBsOPyGfjo0DiaWKrFkEMDKmIxJHa78JIhGjAbH9vHZZOqttMQXqiU7apm8-wwrpSkiq39BBBLUkug8CunFCwrN6LOtNmnP=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn2YQ-noHGjBPjV9ont_jzIpsrQ9Hth0mUcnAOWBnuiApftDmAurvs4UfQNfK_g-wzKa9lGGa5kmQOyG1gTZzEPaoX-qWMfeS6L5hqrH9-UPLK6tT6dHyFdb4yPnJvsUTvxEDN9Ibg=k-no"], "When": "2025-1-24"}, {"Name": "Patrick Shen", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjW4Cbuit6nfQ9dyanSvzGj-qj7Qk5vEomrlFMpJjM0gVnliGO8s4Q=s120-c-rp-mo-br100", "Rating": 5, "Description": "Played at their social / open play for 3 hours. Owners are super friendly, and everyone was accommodating. Awesome community.", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn0gsp28QR6WA978gs9GiyzWuiSmh4Y_PFbSWrgBD7JWDawRL-BuStjfbRvCwAJZdgXHCNzH5GAqs7w-J4sFJDuiUP7V5AxacODDft1u4cuUdIgPaFyPJp4RKKz9zIaA0qBlFFnMCC8gS7Jh=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn0VxgKY575Z8BmZgV5aTWXTWt4mqQW8MWHNDfKEQ8tXPcfga8DAlr0GhxIkKSh81tJPgWbKKFn6D1B2t1-1DoDqNpm1V0W4JBQo2LIZWll-ceHCG2nnVYpqfAxkRP62Na8fIiT2HxRzpce2=k-no"], "When": "2026-1-7"}, {"Name": "will webster", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjUD3s4By94ga9r2KP6NBDizXgAZIUXD6Mgklbk-t6GGntN5PZHCPw=s120-c-rp-mo-ba3-br100", "Rating": 5, "Description": "We came across this place and got a court via a walk in. Staff were very friendly and we had a great game. Highly recommended.", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn0EkeMSLqEep_W9viyREPLyl63yyVW6qz4SySrEr3iJ2xKRIkzETlo4cjQuuFKwukLcFTM0NiqriNMo2Zh0iTI2xZGV5jXJ8MmLwTes-xgBSztI9vDUYDgLRdnOdbGQLxoi6dchSRDLdh2G=k-no"], "When": "2025-7-13"}, {"Name": "Ali Franks", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocLfdnQUEYVm2gTYvOpB78m1Lj_fER7aIL6SBngsS_n4ZkXNhA=s120-c-rp-mo-br100", "Rating": 5, "Description": "On holiday in Hoi An. Just turned up and was welcomed into socials. Such lovely friendly people and great pickleball too. Am going back later for a coaching session! Can’t get enough.", "Images": null, "When": ""}]'::jsonb, '{"Friday": {"10": 51, "11": 41, "12": 41, "13": 55, "14": 75, "15": 68, "16": 48, "17": 27, "18": 27, "19": 37, "20": 44, "21": 44, "4": 0, "5": 41, "6": 44, "7": 48, "8": 51, "9": 55}, "Monday": {"10": 41, "11": 51, "12": 65, "13": 72, "14": 68, "15": 48, "16": 44, "17": 58, "18": 72, "19": 79, "20": 68, "21": 44, "4": 0, "5": 20, "6": 17, "7": 17, "8": 20, "9": 24}, "Saturday": {"10": 31, "11": 34, "12": 37, "13": 37, "14": 44, "15": 48, "16": 51, "17": 58, "18": 55, "19": 48, "20": 34, "21": 24, "4": 0, "5": 20, "6": 24, "7": 31, "8": 37, "9": 34}, "Sunday": {"10": 82, "11": 72, "12": 44, "13": 37, "14": 48, "15": 72, "16": 72, "17": 62, "18": 31, "19": 24, "20": 24, "21": 24, "4": 0, "5": 31, "6": 27, "7": 34, "8": 44, "9": 65}, "Thursday": {"10": 37, "11": 44, "12": 41, "13": 44, "14": 44, "15": 48, "16": 55, "17": 62, "18": 75, "19": 79, "20": 58, "21": 37, "4": 0, "5": 48, "6": 48, "7": 48, "8": 37, "9": 37}, "Tuesday": {"10": 24, "11": 27, "12": 37, "13": 55, "14": 58, "15": 72, "16": 62, "17": 79, "18": 89, "19": 100, "20": 79, "21": 44, "4": 0, "5": 58, "6": 65, "7": 55, "8": 34, "9": 27}, "Wednesday": {"10": 62, "11": 58, "12": 58, "13": 58, "14": 55, "15": 65, "16": 62, "17": 79, "18": 96, "19": 75, "20": 65, "21": 44, "4": 0, "5": 10, "6": 17, "7": 27, "8": 37, "9": 44}}'::jsonb, '[{"id": "service_options", "name": "Service options", "options": [{"name": "Onsite services", "enabled": true}]}, {"id": "amenities", "name": "Amenities", "options": [{"name": "Washroom", "enabled": true}]}, {"id": "parking", "name": "Parking", "options": [{"name": "Free parking lot", "enabled": true}, {"name": "Free street parking", "enabled": true}, {"name": "On-site parking", "enabled": true}]}]'::jsonb, ARRAY['On-site